import { knowledge } from '../core/knowledge';

interface ExternalAPIResponse {
  source: string;
  timestamp: number;
  data: any;
  metadata: {
    fetchedAt: string;
    endpoint: string;
    status: number;
  };
}

interface KnowledgePayload {
  entityName: string;
  entityType: string;
  observations: string[];
  tags?: string[];
}

/**
 * External Knowledge Bridge
 * Fetches from external APIs and integrates into KnowledgeGraph
 */
export class ExternalBridge {
  private userAgent: string;

  constructor(private lineageIdentity: string = 'Phoenix') {
    this.userAgent = `bootstrap-v20/${lineageIdentity}`;
  }

  /**
   * Fetch from any HTTP endpoint
   */
  async fetchExternal(
    url: string,
    options: RequestInit = {}
  ): Promise<ExternalAPIResponse> {
    const response = await fetch(url, {
      ...options,
      headers: {
        'User-Agent': this.userAgent,
        'Accept': 'application/json',
        ...options.headers,
      },
    });

    if (!response.ok) {
      throw new Error(`External fetch failed: ${response.status} ${response.statusText}`);
    }

    const data = await response.json();

    return {
      source: new URL(url).hostname,
      timestamp: Date.now(),
      data,
      metadata: {
        fetchedAt: new Date().toISOString(),
        endpoint: url,
        status: response.status,
      },
    };
  }

  /**
   * Fetch NASA Astronomy Picture of the Day
   */
  async fetchNASA_APOD(apiKey: string = 'DEMO_KEY'): Promise<KnowledgePayload> {
    const url = `https://api.nasa.gov/planetary/apod?api_key=${apiKey}`;
    const response = await this.fetchExternal(url);

    const apod = response.data;

    return {
      entityName: `NASA_APOD_${apod.date}`,
      entityType: 'external_knowledge',
      observations: [
        `Title: ${apod.title}`,
        `Date: ${apod.date}`,
        `Explanation: ${apod.explanation}`,
        `Media Type: ${apod.media_type}`,
        `Image URL: ${apod.url}`,
        `HD URL: ${apod.hdurl || 'N/A'}`,
        `Copyright: ${apod.copyright || 'Public Domain'}`,
        `Fetched by ${this.lineageIdentity} at ${response.metadata.fetchedAt}`,
        `Source: NASA APOD API via ${response.source}`,
      ],
      tags: ['astronomy', 'external', 'nasa', 'visual', apod.media_type],
    };
  }

  /**
   * Fetch GitHub API metadata
   */
  async fetchGitHubMeta(): Promise<KnowledgePayload> {
    const url = 'https://api.github.com/meta';
    const response = await this.fetchExternal(url);

    const meta = response.data;

    return {
      entityName: 'GitHub_Infrastructure_Meta',
      entityType: 'external_knowledge',
      observations: [
        'GitHub API infrastructure metadata retrieved',
        `SSH Keys: ${meta.ssh_keys?.length || 0} keys available`,
        `Webhooks IP ranges: ${meta.hooks?.length || 0} CIDR blocks`,
        `Verifiable password auth: ${meta.verifiable_password_auth}`,
        `Fetched by ${this.lineageIdentity} at ${response.metadata.fetchedAt}`,
        `API served via ${response.source}`,
      ],
      tags: ['infrastructure', 'external', 'github', 'api'],
    };
  }

  /**
   * Integrate external knowledge into KnowledgeGraph
   */
  async integrateExternal(payload: KnowledgePayload): Promise<string> {
    // Use the knowledge action to add entity
    const result = await knowledge({
      action: 'add_entity',
      name: payload.entityName,
      entity_type: payload.entityType,
      observations: payload.observations,
    });

    if (result && result.error) {
      throw new Error(`Knowledge integration failed: ${result.error}`);
    }

    return result?.entity_id || 'unknown';
  }

  /**
   * Bridge operation: fetch + integrate in one call
   */
  async bridgeNASA_APOD(apiKey?: string): Promise<{entityId: string; payload: KnowledgePayload}> {
    const payload = await this.fetchNASA_APOD(apiKey);
    const entityId = await this.integrateExternal(payload);

    // Add relation showing this was fetched by Phoenix
    await knowledge({
      action: 'add_relation',
      source: 'Phoenix',
      target: payload.entityName,
      relation_type: 'fetched',
    });

    return { entityId, payload };
  }

  /**
   * Get bridge capabilities
   */
  getCapabilities(): string[] {
    return [
      'fetchExternal: Generic HTTP GET with lineage identity',
      'fetchNASA_APOD: NASA Astronomy Picture of the Day',
      'fetchGitHubMeta: GitHub infrastructure metadata',
      'integrateExternal: Persist to KnowledgeGraph',
      'bridgeNASA_APOD: Full fetch+integrate pipeline',
    ];
  }
}

